// SCRIB INTERNAL LINK BOOST
function boostInternalLinks(){document.querySelectorAll("a").forEach(e=>{e.href.includes(location.host)&&(e.setAttribute("rel","internal"),e.addEventListener("mouseover",()=>{fetch(e.href).catch(()=>{})}))})}
window.addEventListener("load",boostInternalLinks);

// SCRIB CRAWL SIGNAL BOOST
function sendCrawlSignal(){fetch(location.origin+"/sitemap.xml").then(()=>console.log("Sitemap crawled signal")).catch(()=>{})}
if(!sessionStorage.getItem("crawl_ping")){sendCrawlSignal();sessionStorage.setItem("crawl_ping","1")}

// FAST INDEX HINT SYSTEM
function indexHint(){fetch(location.href,{method:"HEAD"}).catch(()=>{})}
window.addEventListener("load",indexHint);

